                <style>
                    .gt-recent-versions[data-gt-recent-collapsed="1"] li:nth-child(n+6) {
                        display: none;
                    }
                </style>
                <script>
                (function () {
                    var btn  = document.querySelector('.gt-recent-versions-toggle');
                    var list = document.querySelector('.gt-recent-versions');
                    if (!btn || !list) return;
                    btn.addEventListener('click', function () {
                        var collapsed = list.getAttribute('data-gt-recent-collapsed') === '1';
                        if (collapsed) {
                            list.removeAttribute('data-gt-recent-collapsed');
                            btn.textContent = btn.getAttribute('data-label-hide');
                        } else {
                            list.setAttribute('data-gt-recent-collapsed', '1');
                            btn.textContent = btn.getAttribute('data-label-show');
                        }
                    });
                }());
                </script>

